import cv2
import matplotlib.pyplot as plt
import numpy as np

import geosat.image.image_processing as ip


def compute_diameter(radius, scale):
    return int(2 * radius * scale + 1)


def compute_shape(radius, scale):
    diameter = compute_diameter(radius, scale)
    return diameter, diameter


def show_image(image, title):
    plt.imshow(image)
    plt.title(title)
    plt.show()


def extract_high_intensity_mask(image, gsd=0.05, show=False):
    """Returns a mask which contains the features with the highest intensities on the intensity image 'image'"""
    if show:
        show_image(image, "Raw image")

    s = 0.05 / gsd
    high_pass_radius = 15
    mask = np.isnan(image)
    image[mask] = -np.inf
    image = ip.extend_border(image, iterations=high_pass_radius * 2)
    if show:
        show_image(image, "Extending border to avoid side effects")

    image = (image * 255).astype(np.uint8)
    image = cv2.morphologyEx(
        image,
        cv2.MORPH_TOPHAT,
        cv2.getStructuringElement(cv2.MORPH_ELLIPSE, compute_shape(10, s)),
    )
    if show:
        show_image(image, "Background low frequency deletion")

    structuring = cv2.getStructuringElement(cv2.MORPH_ELLIPSE, compute_shape(1, s))
    high_pass_kernel = ip.generate_high_pass_kernel(
        compute_diameter(high_pass_radius, s)
    )
    image = cv2.filter2D(image, cv2.CV_16S, high_pass_kernel)
    image[mask] = 0
    if show:
        show_image(image, "Foreground / background contrast increase")

    image = (np.clip(image, 0, None) // 128).astype("uint8")
    _, image = cv2.threshold(image, 0, 255, cv2.THRESH_OTSU)
    if show:
        show_image(image, "Thresholding")

    image = ip.fill_holes(image, count=5, mask=mask).astype(np.uint8)
    if show:
        show_image(image, "Holes filling on no-data pixels")

    image = ip.conditional_opening(image, structuring)
    if show:
        show_image(
            image, "Suppression of the noise without separating connected components"
        )

    image = ip.fill_holes(image)
    if show:
        show_image(image, "Hole filling without modifying connectivity")
    return image.astype(np.uint8) * 255
